1620     if (match(U, m_ExtractValue<0>(m_Value()))) {
1621       if (!Sub)
1622         Sub = Builder.CreateSub(A, B);
1623       U->replaceAllUsesWith(Sub);
1624       Changed = true;
1625     } else if (match(U, m_ExtractValue<1>(m_Value()))) {
1626       U->replaceAllUsesWith(Builder.getFalse());
1627       Changed = true;
1628     } else
1629       continue;
